"use client"

import * as React from "react"
import { cn } from "@/lib/utils"
import { UpIcon } from "@/icons"

/* =============================================================================
   FormSection - 섹션 (타이틀 + 접기 + 구분선)
   ============================================================================= */

interface FormSectionProps extends React.HTMLAttributes<HTMLDivElement> {
  /** 섹션 타이틀 */
  title?: string
  /** 헤더 우측 영역 (버튼 등) */
  headerRight?: React.ReactNode
  /** 접기/펼치기 가능 여부 */
  collapsible?: boolean
  /** 기본 접힘 상태 */
  defaultCollapsed?: boolean
  /** 구분선 표시 여부 (섹션 위에 표시) */
  divider?: boolean
  /** 전체 너비 사용 (FormContent 내에서 col-span-full 적용) */
  fullWidth?: boolean
}

const FormSection = React.forwardRef<HTMLDivElement, FormSectionProps>(
  (
    {
      className,
      title,
      headerRight,
      collapsible = false,
      defaultCollapsed = false,
      divider = false,
      fullWidth = false,
      children,
      ...props
    },
    ref
  ) => {
    const [isCollapsed, setIsCollapsed] = React.useState(defaultCollapsed)

    const handleToggle = () => {
      if (collapsible) {
        setIsCollapsed(!isCollapsed)
      }
    }

    return (
      <div
        ref={ref}
        className={cn(
          "flex flex-col gap-2",
          fullWidth && "col-span-full",
          className
        )}
        {...props}
      >
        {/* 구분선 */}
        {divider && (
          <div className="py-3">
            <div className="h-px bg-border" />
          </div>
        )}

        {/* 섹션 헤더 */}
        {(title || headerRight) && (
          <div className="flex h-6 items-center justify-between">
            {collapsible ? (
              <button
                type="button"
                className="flex items-center gap-2 cursor-pointer select-none"
                onClick={handleToggle}
                aria-expanded={!isCollapsed}
              >
                <span className="text-base font-medium text-text-primary">
                  {title}
                </span>
                <UpIcon
                  size={24}
                  className={cn(
                    "text-text-secondary transition-transform duration-200",
                    isCollapsed && "rotate-180"
                  )}
                />
              </button>
            ) : (
              <span className="text-base font-medium text-text-primary">
                {title}
              </span>
            )}
            {headerRight && <div>{headerRight}</div>}
          </div>
        )}

        {/* 섹션 컨텐츠 */}
        <div
          className={cn(
            "grid transition-[grid-template-rows,opacity] duration-200 ease-in-out",
            isCollapsed ? "grid-rows-[0fr] opacity-0" : "grid-rows-[1fr] opacity-100"
          )}
        >
          <div className="overflow-hidden">
            <div className="flex flex-col gap-2">
              {children}
            </div>
          </div>
        </div>
      </div>
    )
  }
)
FormSection.displayName = "FormSection"

/* =============================================================================
   FormRow - 필드 행 (1~4열 그리드)
   ============================================================================= */

interface FormRowProps extends React.HTMLAttributes<HTMLDivElement> {
  /** 열 수 (1, 2, 3, 4) */
  columns?: 1 | 2 | 3 | 4
}

const formRowColumnStyles = {
  1: "grid-cols-1",
  2: "grid-cols-2",
  3: "grid-cols-3",
  4: "grid-cols-4",
} as const

const FormRow = React.forwardRef<HTMLDivElement, FormRowProps>(
  ({ className, columns = 1, children, ...props }, ref) => {
    return (
      <div
        ref={ref}
        className={cn(
          "grid gap-2",
          formRowColumnStyles[columns],
          className
        )}
        {...props}
      >
        {children}
      </div>
    )
  }
)
FormRow.displayName = "FormRow"

export { FormSection, FormRow }
export type { FormSectionProps, FormRowProps }
